// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門開的那一秒，冷風灌進來。不是自然風，是月台通風系統吹出來的、帶著混凝土和金屬味的冷氣。澪的眼睛被外面的燈光刺了一下——比車廂裡亮，比車廂裡白，白到所有東西都失去了厚度。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門外站著的人比她預期的多。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最前面是兩個穿反光背心的鐵道安全人員，手裡拿著對講機和一根伸縮桿。他們身後是救護人員，一個推著擔架，一個拎著急救箱。再後面是穿制服的控制中心人員，手裡拿著平板，螢幕上亮著列車平面圖。最外圍，還有更多腳步聲在靠近——她聽得出來，那種鞋底硬、步頻快、帶著對講機雜音的腳步，是警察。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "第七車乘客，請雙手舉起，遠離傷者。不要再碰地上的金屬物。不要靠近車門。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從月台的喇叭播出來的，不是車廂裡那個合成女聲了。是一個男人的聲音，透過擴音器，帶著一點回音。語氣比合成女聲急，但指令是一樣的——舉手、退後、不要碰、不要靠近。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是在救他——", background: Background.Chapter_3_Ch3_Act2_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.RailwaySafety, character: "鐵道安全人員", dialogue: "小姐，先照做。雙手舉起，退到車門邊。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想解釋。她張嘴了。但對方沒有在聽她說什麼，對方在看她手上的血。安全人員的視線落在她舉起的雙手上——掌心朝外，血從指縫往下走，袖口內側洇開的那片深色在冷光下格外明顯。他看的不是她的表情。是她的手。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退到車門邊。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "救護人員從她身側擠過去，兩個人，動作很快，沒有看她。他們直奔千田。一個人蹲下來檢查頸動脈，另一個人開始剪他的外套——剪刀沿著拉鏈內側往上走，布料被撐開的聲音在安靜的車廂裡很清楚。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪被擋在人群外面。她退後了一步，又一步，背靠到車門旁的牆板上。從人和人之間的縫隙裡，她看見了一瞬間。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的外套被剪開。內側露出一塊白色的東西——膠布，或者摺起來的布料，邊緣已經翹起，黏性失效。血不是從一個新鮮的傷口噴出來的。是早就浸在衣服裡的，深到發黑，邊緣乾涸發暗，像已經在那裡待了很久。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她看見座位邊緣。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "血痕的起點。她剛才以為血是從千田大腿外側開始往下流的。但從這個角度看——救護人員把他身體往前搬的時候，座椅靠背和坐墊的交界處露出來了——血痕的起點比她以為的位置更低。不是大腿外側。是更低。是肋下往後延伸的方向。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)血不是從我碰到的地方開始的。", background: Background.Chapter_3_Ch3_Act2_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個念頭閃過去，還沒來得及成形，就被一個聲音蓋住了。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.RailwaySafety, character: "鐵道安全人員", dialogue: "小姐，請過來這邊。不要看那裡。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她被引導著走出車門。腳踩到月台地面的那一刻，感覺和車廂裡完全不同——混凝土，硬的，冷的，沒有車廂地板那種被計算過的減震。她的膝蓋有點軟，但沒有倒。", background: Background.Chapter_3_Ch3_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安全人員沒有碰她。他們保持著一個手臂的距離，用手勢指引她站到月台邊牆的位置。她的雙手還舉著。掌心朝外。血已經開始乾了，在指縫裡變成暗褐色，牽出細絲。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個控制中心的人員走過來，手裡拿著平板，螢幕上是第七車的平面圖。他看了一眼車廂內部，在平板上點了幾下，然後對安全人員說了一句她聽不太懂的話——「中央流已截取，標記位置」。她不知道「中央流」是什麼。她只聽見「標記位置」。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她看見安全人員走向車廂裡那塊銀色外殼。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有直接拿起來。他從腰間取出一個透明防護罩——像一個硬質的透明盒蓋——罩在外殼上方，把它隔離在地板上。外殼在罩子底下，破邊朝上，金色接點朝上，血下面的痕跡朝上。她隔著透明塑膠還能看見它。但已經不能碰了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警察到了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是一個。是三個。兩個穿制服，一個穿便衣。便衣那個手裡拿著一個透明的證物袋和一雙手套。他戴上手套的動作很慢——不是慎重，是習慣。像每天都要做很多次的事。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鑑識人員從安全人員手裡接過了外殼。他掀開防護罩，用戴著手套的手把外殼拾起來，翻了一面，看了看，然後放進透明證物袋裡。封口。貼標籤。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "標籤是手寫的。黑色奇異筆，字跡方正。澪站的位置離得不遠，她看得見上面的字。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現場暫稱：刃物狀金屬片 / 第七車 / 朝倉澪手邊發現。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)刃物。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刀。他們寫的是刀。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯那不是刀。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說出來了。聲音比她預期的大，在月台上彈了一下。旁邊的安全人員轉頭看她。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那不是刀。是他⋯⋯是他塞給我的。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見自己的話在空氣裡停了一秒。然後她意識到——這句話聽起來是什麼意思。「是他給我的。」她承認了。她承認她拿著它。她承認她知道它在那裡。她想把意思修正回來，但嘴巴已經比腦子慢了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "便衣警察看了她一眼。沒有接話。他在證物袋上又寫了一行字，然後把袋子裝進一個更大的不透明夾鏈袋裡。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外殼消失了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是物理意義上的消失。它被裝進了袋子，袋子被放進了箱子，箱子被一個制服警察提走了。從澪的視線裡，它就是消失了。像一樣東西從她的世界裡被剪下來，貼進了另一個世界。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他們開始處理她。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個救護人員走過來，讓她把手放下來。他看了看她的雙手——不是在檢查她有沒有受傷，是在看血跡分布。他拿出手機，拍了一張。又拍了一張。閃光燈在月台的冷光裡顯得多餘，但還是閃了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鑑識人員也過來了。他用棉片在她掌心擦了一下，在指甲縫裡轉了一下，在袖口內側按了一下。每一個動作都配一個編號。他嘴裡在念，旁邊有人在記。她不知道他們在收集什麼。她只知道她救人的痕跡正在被編號、採樣、裝進袋子。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是外套。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "外套請脫下來。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的外套。深色的、袖口沾了血的那件。她穿著它上了車，穿著它按了緊急通話鈕，穿著它壓了千田的傷口。袖口內側洇開的那片深色在冷風裡已經變硬了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她脫了。手臂從袖管裡抽出來的時候，她打了一個冷顫——不是因為冷，是因為脫掉外套之後，她突然意識到自己裡面的衣服是乾淨的。只有手和外套是髒的。身體是乾淨的。這應該說明什麼。她不知道現在有没有人在意這件事。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外套被裝進另一個透明證物袋。封口。標籤。她沒有去看標籤上寫了什麼。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個站務人員走過來，遞給她一件外套。薄的，灰色的，拉鏈款，像備用品。她接過來穿上。拉鏈拉到一半的時候她的手停了。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)包。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的斜背包。剛才在車廂裡，她按緊急通話鈕的時候，背包從肩上滑下來，落在地板上。她沒有去管它。後來她蹲下放外殼的時候，背包還在地板上。她出車門的時候——", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)我的包呢？", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回頭看了一眼車廂。背包還在裡面，在地板上，靠近座椅腿的位置。一個安全人員正要把它拿起來。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那是⋯⋯那是我的包。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音比她預期的急。安全人員停下來，看了看包，又看了看她。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.RailwaySafety, character: "鐵道安全人員", dialogue: "裡面有沒有危險物品？", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安全人員把背包拿起來，拉開主夾層看了一眼。沒有翻內層。沒有摸小布套。他把包遞給她。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪接過背包的時候，手指先碰到了最內層。那個小布套還在。隔著布料，她感覺得到裡面那個硬的、薄的、圓的東西。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小鏡子。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不在外套裡。在斜背包最內層的小布套中。外套被收走的時候，她沒有感覺。但現在背包回到手上的時候，她感覺到了——像一個人在水裡摸到了一塊浮木。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)還在。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把背包掛回肩上。拉鏈拉上。她不知道為什麼，在這一刻，在千田被救護人員剪開外套、在血衣被封袋、在外殼被寫成「刃物狀金屬片」之後，她唯一感到的慶幸是——至少悠真留下的東西還沒有被裝進透明袋裡。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她聽見車廂裡傳來救護人員的聲音。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Paramedic, character: "救護人員", dialogue: "心肺停止。意識不明。準備搬運。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "八個字。平的。像在讀一個表格欄位。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田被搬上擔架的時候，澪看見他的臉。灰白的。眼睛閉上了——她不記得是誰幫他閉上的。他的外套被剪開的兩片垂在擔架兩側，內側那塊白色膠布在燈光下晃了一下，像一面被撕下來的貼紙。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "擔架推過她面前的時候，她又看見了一個東西。只一秒。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "座位邊緣。救護人員把千田搬起來之後，座椅上留下一灘血。那灘血的形狀不對——不是從坐姿的位置往下積的。是從靠背和坐墊的交界處、從更低的位置開始，往坐墊前方蔓延的。血痕的起點比她以為的更低。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他上車的時候就已經在流血了。", background: Background.Chapter_3_Ch3_Act2_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個念頭比剛才更清楚了。但她沒有時間想。擔架已經推走了。安全人員在拉封鎖帶。一個警察走過來，站在她面前。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "朝倉澪小姐，請跟我們到站務室。需要做筆錄。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是詢問。是通知。語氣不算凶，但沒有留空間。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看了一眼身後的第七車。車門還開著，裡面的燈還亮著，座椅上的血痕在白光下像一幅被展開的、她看不懂的圖。", background: Background.Chapter_3_Ch3_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車門開了。她從車廂裡出來了。但她沒有覺得自己到了外面。她只是從一個系統，被移交給了另一個系統。", background: Background.Chapter_3_Ch3_Act2_S1 },
];
